def gen(rng, size):
    ops = ['WordDictionary']
    args = [[]]
    added = []
    for _ in range(max(1, size)):
        if not added or rng.random() < 0.5:
            ln = rng.randint(1, 5)
            w = ''.join(rng.choice('abc') for _ in range(ln))
            added.append(w)
            ops.append('addWord'); args.append([w])
        else:
            base = rng.choice(added)
            chars = list(base)
            ndots = rng.randint(0, min(2, len(chars)))
            for pos in rng.sample(range(len(chars)), ndots):
                chars[pos] = '.'
            if rng.random() < 0.3 and chars:
                chars[rng.randrange(len(chars))] = rng.choice('xyz')
            ops.append('search'); args.append([''.join(chars)])
    return [ops, args]

