class WordDictionary:
    def __init__(self):
        self.root = {}
    def addWord(self, word):
        node = self.root
        for c in word:
            node = node.setdefault(c, {})
        node['$'] = True
    def search(self, word):
        def dfs(node, i):
            if i == len(word):
                return '$' in node
            c = word[i]
            if c == '.':
                for k, child in node.items():
                    if k != '$' and dfs(child, i + 1):
                        return True
                return False
            if c in node:
                return dfs(node[c], i + 1)
            return False
        return dfs(self.root, 0)

